=New email at Tribal Cowboy
From: {{ $json.sender_name }}
Subject: {{ $json.subject }}

Council review + draft reply on its way to your inbox.

parameters.jsCode:
const emailData = $('Extract Email Data').item.json;
const councilReview = $('Build Draft Prompt').item.json.council_review;
const emailDraft = $input.item.json.text;

// Extract key fields from council review
const get = (pattern) => { const m = councilReview.match(pattern); return m ? m[1].trim() : ''; };
const priority = get(/\*\*Priority:\*\*\s*([^\n*]+)/i) || get(/Priority:\s*([^\n]+)/i) || 'Normal';
const category = get(/\*\*Category:\*\*\s*([^\n*]+)/i) || get(/Category:\s*([^\n]+)/i) || 'Email';
const verdict = get(/\*\*Council Verdict:\*\*\s*([\s\S]*?)(?=\*\*Response Strategy|\*\*Next Action|\*\*Response Strat|$)/i);
const nextAction = get(/\*\*Next Action:\*\*\s*([^\n]+)/i);

const priorityColor = { urgent:'#C0392B', high:'#D4850A', normal:'#2D6A6A', low:'#888' }[priority.toLowerCase()] || '#2D6A6A';

const esc = (s) => (s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const fmt = (s) => esc(s).replace(/\*\*(.+?)\*\*/g,'<strong>$1</strong>').replace(/\n/g,'<br>');

const subject = '[TC Email Alert] ' + (emailData.subject || 'no subject') + ' — ' + priority;

const html = `<!DOCTYPE html><html><head><meta charset="utf-8"><style>
body{font-family:-apple-system,Arial,sans-serif;background:#f0f0f0;margin:0;padding:16px}
.w{max-width:580px;margin:0 auto}
.card{background:#fff;border-radius:8px;margin-bottom:12px;overflow:hidden;box-shadow:0 1px 3px rgba(0,0,0,.1)}
.hdr{background:#2D6A6A;color:#fff;padding:16px 20px}
.hdr h2{margin:0 0 4px;font-size:17px;font-weight:700}
.hdr p{margin:0;font-size:13px;opacity:.8}
.badges{padding:10px 20px;border-bottom:1px solid #f0f0f0}
.badge{display:inline-block;padding:3px 10px;border-radius:20px;color:#fff;font-size:11px;font-weight:700;margin-right:6px}
.sec{padding:14px 20px}
.lbl{font-size:10px;font-weight:800;letter-spacing:1.5px;color:#aaa;text-transform:uppercase;margin-bottom:8px}
.action{background:#fff8e6;border-left:4px solid #C9A84C;padding:12px 14px;border-radius:0 6px 6px 0;font-weight:600;font-size:15px;line-height:1.5}
.verdict{background:#f0f7f7;border-left:4px solid #2D6A6A;padding:12px 14px;border-radius:0 6px 6px 0;font-size:14px;line-height:1.6}
.draft{background:#fafafa;border:1px solid #e0e0e0;border-radius:6px;padding:16px;font-size:14px;line-height:1.8;font-family:Georgia,serif;white-space:pre-wrap}
.orig{background:#f9f9f9;border:1px solid #eee;border-radius:6px;padding:12px;font-size:13px;color:#666;line-height:1.6;white-space:pre-wrap}
.full{font-size:13px;color:#555;line-height:1.7}
.foot{text-align:center;font-size:11px;color:#bbb;padding:10px}
</style></head><body><div class="w">

<div class="card">
  <div class="hdr"><h2>📧 ${esc(emailData.sender_name)}</h2><p>${esc(emailData.subject || '(no subject)')}</p></div>
  <div class="badges">
    <span class="badge" style="background:${priorityColor}">${esc(priority)}</span>
    <span class="badge" style="background:#555">${esc(category)}</span>
    <span style="font-size:11px;color:#999">${esc(emailData.received_at)}</span>
  </div>
</div>

${nextAction ? `<div class="card"><div class="sec"><div class="lbl">👆 What To Do Next</div><div class="action">${fmt(nextAction)}</div></div></div>` : ''}

<div class="card"><div class="sec"><div class="lbl">✏️ Draft Reply — Copy, Edit &amp; Send</div><div class="draft">${fmt(emailDraft)}</div></div></div>

${verdict ? `<div class="card"><div class="sec"><div class="lbl">🏛️ Council Verdict</div><div class="verdict">${fmt(verdict)}</div></div></div>` : ''}

<div class="card"><div class="sec"><div class="lbl">📩 Original Email</div><div style="font-size:12px;color:#999;margin-bottom:8px">From: ${esc(emailData.sender_email)}</div><div class="orig">${fmt(emailData.body)}</div></div></div>

<div class="card"><div class="sec"><div class="lbl">📋 Full Council Review</div><div class="full">${fmt(councilReview)}</div></div></div>

<div class="foot">Tribal Cowboy AI — Review before sending</div>
</div></body></html>`;

return [{ json: { subject, html } }];
